<?php
require_once __DIR__.'/../app/bootstrap.php';
require_once __DIR__.'/../app/schema.php';
if(installed()) redirect('/admin/'); $err='';
if($_SERVER['REQUEST_METHOD']==='POST'){ try{ $host=trim($_POST['db_host']);$name=trim($_POST['db_name']);$user=trim($_POST['db_user']);$pass=(string)$_POST['db_pass']; $pdo=new PDO("mysql:host=$host;dbname=$name;charset=utf8mb4",$user,$pass,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]); create_schema($pdo); $cfg="<?php\nreturn ['db'=>['host'=>'".addslashes($host)."','name'=>'".addslashes($name)."','user'=>'".addslashes($user)."','pass'=>'".addslashes($pass)."']];\n"; file_put_contents(CONFIG_FILE,$cfg,LOCK_EX); require CONFIG_FILE; db(); create_schema(db()); seed_settings(['site_name'=>$_POST['site_name'],'site_description'=>$_POST['site_description']]); $st=db()->prepare('INSERT INTO admins(username,password_hash,created_at) VALUES(?,?,NOW())'); $st->execute([trim($_POST['admin_user']),password_hash((string)$_POST['admin_pass'],PASSWORD_DEFAULT)]); redirect('/admin/login.php'); }catch(Throwable $e){$err='インストールに失敗しました。入力内容とDB権限を確認してください。'; @unlink(CONFIG_FILE);} }
?><!doctype html><html lang=ja><head><meta charset=utf-8><link rel=stylesheet href="<?=e(url_path('/assets/admin.css'))?>"><title>Install</title></head><body><main style="margin:0 auto;max-width:760px"><h1>livedoorアンテナ インストール</h1><?php if($err)echo'<p class="notice error">'.e($err).'</p>';?><form method=post><?php foreach(['db_host'=>'DBホスト','db_name'=>'DB名','db_user'=>'DBユーザー','db_pass'=>'DBパスワード','admin_user'=>'管理者ユーザー名','admin_pass'=>'管理者パスワード','site_name'=>'サイト名','site_description'=>'サイト説明'] as $n=>$l){echo'<label>'.e($l).'<input name='.$n.($n==='db_pass'||$n==='admin_pass'?' type=password':'').' required></label>';}?><button>インストール</button></form></main></body></html>
